INSERT INTO questions (id, specialty, category, domain_name, subtopic, difficulty, stem, choices, correct_answer, explanation, "references", status, telemetry) VALUES
('authored-batch-r3-031', 'Orthopedic, Urology & GYN', 'Orthopedic, Urology & GYN', 'Subspecialty Care', 'Urology: TURP syndrome (dilutional hyponatremia from irrigation fluid absorption)', 'medium', 'A 72-year-old man with benign prostatic hyperplasia undergoes monopolar transurethral resection of the prostate (TURP) under spinal anesthesia with 1.5% glycine irrigation. About 50 minutes into the resection, he becomes restless and reports nausea and blurred vision, then complains of a headache. His blood pressure rises to 168/96 mmHg, heart rate falls to 52/min, and SpO2 is 97% on supplemental oxygen. A stat serum sodium returns at 118 mEq/L. Which of the following is the most appropriate next step in management?', '[{"text":"Ask the surgeon to stop the resection and irrigation, then begin 3% hypertonic saline at approximately 1 mL/kg/hr","label":"A","correct":true,"rationale":"Correct: this patient has symptomatic, severe TURP-syndrome hyponatremia, so the irrigant absorption source must be halted and slow correction with hypertonic saline initiated while limiting the rise to about 10 mEq/L per 24 hours."},{"text":"Rapidly infuse 1 liter of 0.9% normal saline to restore the sodium toward normal","label":"B","correct":false,"rationale":"Incorrect: isotonic saline corrects sodium far too slowly for symptomatic severe hyponatremia and adds volume to an already fluid-overloaded patient."},{"text":"Administer atropine and continue the resection while monitoring the sodium","label":"C","correct":false,"rationale":"Incorrect: treating only the bradycardia while continuing irrigation allows further hypotonic fluid absorption and progression toward seizures, coma, and death."},{"text":"Give 0.5 mEq/kg of sodium bicarbonate to correct the presumed acidosis","label":"D","correct":false,"rationale":"Incorrect: the problem is dilutional hyponatremia and cerebral edema, not acidosis, and bicarbonate does not address the sodium deficit or the ongoing absorption."},{"text":"Restrict all intravenous and irrigation fluids and observe without sodium therapy","label":"E","correct":false,"rationale":"Incorrect: passive fluid restriction is inadequate for a symptomatic patient at 118 mEq/L who needs active, controlled sodium correction to prevent cerebral herniation."}]'::jsonb, 'A', 'TURP syndrome results from intravascular absorption of hypotonic irrigation fluid through open prostatic venous sinuses, producing dilutional hyponatremia, volume overload, and cerebral edema; glycine solutions add hyperammonemia and transient visual disturbances. The first step is always to stop the irrigation/resection source, secure oxygenation, and obtain a stat sodium. Symptomatic severe hyponatremia (e.g., 118 mEq/L with neurologic signs) warrants 3% saline at about 1 mL/kg/hr with the correction capped near 10 mEq/L per 24 hours to avoid osmotic demyelination.', '[{"url":"https://www.openanesthesia.org/keywords/hyponatermia-and-transurethral-resection-of-prostate-syndrome/","source":"Hyponatremia and Transurethral Resection of Prostate Syndrome - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-032', 'Orthopedic, Urology & GYN', 'Orthopedic, Urology & GYN', 'Subspecialty Care', 'Orthopedics: pneumatic tourniquet deflation physiology', 'medium', 'A 24-year-old healthy man undergoes open reduction and internal fixation of a tibial plateau fracture under general anesthesia with a thigh pneumatic tourniquet inflated for 95 minutes. He is volume-replete and normothermic, ventilated to an end-tidal CO2 of 35 mmHg. Immediately after the surgeon deflates the tourniquet, the anesthetist notes the end-tidal CO2 climbs to 48 mmHg over about one minute and the mean arterial pressure falls from 78 to 60 mmHg. Which of the following best explains these findings?', '[{"text":"Acute pulmonary embolism from dislodged deep venous thrombus","label":"A","correct":false,"rationale":"Incorrect: a large PE would classically cause a fall (not a rise) in end-tidal CO2 from increased dead-space ventilation, along with hypoxemia and right-heart strain."},{"text":"Washout of CO2-rich, vasoactive metabolites from the previously ischemic limb into the central circulation","label":"B","correct":true,"rationale":"Correct: reperfusion of the ischemic limb returns accumulated CO2, lactate, and potassium centrally, transiently raising end-tidal CO2 and lowering systemic vascular resistance and arterial pressure."},{"text":"Malignant hyperthermia triggered by the volatile anesthetic","label":"C","correct":false,"rationale":"Incorrect: MH produces a sustained, progressive rise in end-tidal CO2 with hyperthermia, rigidity, and tachycardia rather than a brief spike timed precisely to cuff release."},{"text":"Inadequate minute ventilation from a kinked or disconnected circuit","label":"D","correct":false,"rationale":"Incorrect: a circuit problem is unrelated to tourniquet deflation timing and would not resolve spontaneously as reperfusion metabolites are cleared over several minutes."},{"text":"Light anesthesia causing sympathetic activation and hypercarbia","label":"E","correct":false,"rationale":"Incorrect: light anesthesia typically raises blood pressure and heart rate, whereas this patient shows hypotension coincident with cuff deflation, which is the opposite hemodynamic picture."}]'::jsonb, 'B', 'Release of a lower-extremity pneumatic tourniquet allows CO2-rich, acidotic, hyperkalemic venous blood from the ischemic limb to re-enter the systemic circulation, producing a transient spike in end-tidal CO2 (peaking around one minute and normalizing within about ten minutes) and a fall in central venous pressure and arterial pressure that can persist roughly fifteen minutes. The metabolic washout also causes a brief metabolic acidosis. Anticipatory management includes transiently increasing minute ventilation and ensuring euvolemia before deflation. The hemodynamic dip is usually self-limited but can be marked in hypovolemic patients.', '[{"url":"https://www.openanesthesia.org/keywords/lower-extremity-tourniquet-deflation-physiologic-effects/","source":"Lower extremity tourniquet deflation: Physiologic effects - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-033', 'Orthopedic, Urology & GYN', 'Orthopedic, Urology & GYN', 'Subspecialty Care', 'GYN/laparoscopy: vagal bradyarrhythmia from CO2 pneumoperitoneum insufflation', 'medium', 'A 38-year-old woman with no significant comorbidities undergoes laparoscopic hysterectomy under general anesthesia. Shortly after the surgeon insufflates the abdomen with CO2 to establish pneumoperitoneum, the patient develops sinus bradycardia to 38/min with a brief run of junctional rhythm; blood pressure falls to 84/50 mmHg. SpO2 remains 99% and end-tidal CO2 is stable at 36 mmHg. Which of the following is the most likely cause of this acute event?', '[{"text":"Carbon dioxide venous gas embolism","label":"A","correct":false,"rationale":"Incorrect: a significant CO2 embolism typically causes a sudden fall in end-tidal CO2 with hypoxemia and cardiovascular collapse, whereas this patient''s end-tidal CO2 and saturation are unchanged."},{"text":"Hypercarbia-induced catecholamine surge","label":"B","correct":false,"rationale":"Incorrect: systemic CO2 absorption raises sympathetic tone causing tachycardia and hypertension, the opposite of the bradycardia and hypotension observed."},{"text":"A vagally mediated reflex from acute peritoneal stretch during insufflation","label":"C","correct":true,"rationale":"Correct: rapid distension of the peritoneum at the onset of insufflation can trigger a vagal reflex producing bradyarrhythmias and hypotension, which is the classic timing and presentation here."},{"text":"Tension capnothorax from CO2 tracking into the pleural space","label":"D","correct":false,"rationale":"Incorrect: a capnothorax produces rising airway pressures, hypoxemia, and hemodynamic compromise over time rather than an immediate vagal bradycardia at the moment of insufflation."},{"text":"Endobronchial migration of the endotracheal tube from cephalad diaphragm shift","label":"E","correct":false,"rationale":"Incorrect: mainstem intubation causes hypoxemia and high peak airway pressures, not an abrupt isolated bradyarrhythmia, and the saturation here is normal."}]'::jsonb, 'C', 'At the onset of CO2 pneumoperitoneum, sudden peritoneal stretch can provoke a vagal reflex producing bradycardia, junctional rhythms, or even asystole, particularly with rapid insufflation. Appropriate management is to ask the surgeon to desufflate, treat with an anticholinergic such as atropine, and re-insufflate slowly at a lower pressure. This is distinct from the later sympathetic effects of absorbed CO2 (hypertension, tachycardia) and from CO2 venous embolism, which lowers end-tidal CO2 and oxygen saturation.', '[{"url":"https://www.openanesthesia.org/keywords/anesthesia-for-laparoscopic-and-robotic-surgery/","source":"Anesthesia for Laparoscopic and Robotic Surgery - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-034', 'Regional & Pain', 'Regional & Pain', 'Subspecialty Care', 'Local anesthetic systemic toxicity (LAST) management', 'medium', 'A 68-kg woman undergoes an ultrasound-guided interscalene brachial plexus block with 30 mL of 0.5% ropivacaine for shoulder arthroscopy. About 90 seconds after injection she reports a metallic taste and circumoral numbness, then becomes agitated and has a generalized tonic-clonic seizure, followed by a wide-complex bradycardia with a blood pressure of 70/40 mmHg. The seizure is terminated with midazolam and ventilation is supported with 100% oxygen. In addition to starting chest compressions if a pulse is lost, which intervention is most appropriate as part of her resuscitation?', '[{"text":"Administer a standard ACLS epinephrine dose of 1 mg IV every 3 to 5 minutes","label":"A","correct":false,"rationale":"During local anesthetic systemic toxicity, full ACLS-dose epinephrine can impair lipid resuscitation and worsen arrhythmias, so the dose should be reduced rather than given at the standard 1 mg."},{"text":"Give a calcium channel blocker to control the wide-complex rhythm","label":"B","correct":false,"rationale":"Calcium channel blockers and beta-blockers are specifically discouraged in LAST because they further depress an already compromised myocardium."},{"text":"Administer a propofol infusion to both treat the seizure and provide a lipid load","label":"C","correct":false,"rationale":"Propofol is not a substitute for lipid emulsion; its lipid content is far too low to be therapeutic and its cardiodepressant effect is dangerous in a hypotensive patient."},{"text":"Administer a 1.5 mL/kg bolus of 20% intravenous lipid emulsion followed by an infusion","label":"D","correct":true,"rationale":"Intravenous lipid emulsion is the established standard treatment for LAST, given as an approximately 1.5 mL/kg bolus of the 20% formulation followed by a continuous infusion, and it should be started early once toxicity is recognized."},{"text":"Give vasopressin 40 units IV in place of epinephrine","label":"E","correct":false,"rationale":"Vasopressin is not recommended in LAST resuscitation and has been associated with worse outcomes in this setting, so it should be avoided rather than substituted for epinephrine."}]'::jsonb, 'D', 'This is classic local anesthetic systemic toxicity (LAST): prodromal CNS symptoms (metallic taste, circumoral numbness), a seizure, and cardiovascular collapse shortly after a large-volume plexus injection. The cornerstone of treatment, alongside airway control, seizure suppression with benzodiazepines, and modified ACLS, is intravenous 20% lipid emulsion given as a ~1.5 mL/kg bolus followed by an infusion. During LAST, epinephrine doses should be reduced (to roughly 1 mcg/kg or less), and vasopressin, calcium channel blockers, beta-blockers, and additional local anesthetics should be avoided.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK499964/","source":"Local Anesthetic Toxicity - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-035', 'Regional & Pain', 'Regional & Pain', 'Subspecialty Care', 'Truncal/peripheral nerve block coverage (TAP block)', 'medium', 'A 58-year-old man undergoes an open right hemicolectomy. As part of a multimodal opioid-sparing plan, the surgical team performs bilateral ultrasound-guided transversus abdominis plane (TAP) blocks with local anesthetic. In the recovery unit he reports good relief of pain at his midline and flank incision sites but continues to have deep, cramping pain that he localizes vaguely to the center of his abdomen, with associated nausea. Which statement best explains why the TAP block has not relieved this component of his pain?', '[{"text":"The TAP block was placed too superficially and deposited local anesthetic in the subcutaneous tissue","label":"A","correct":false,"rationale":"A technical failure would also reduce relief of his incisional (somatic) pain, but his wound pain is well controlled, so a misplaced injection does not explain the isolated deep abdominal pain."},{"text":"The TAP block only provides analgesia when combined with intrathecal morphine","label":"B","correct":false,"rationale":"A TAP block produces analgesia on its own from local anesthetic spread to abdominal wall nerves and does not require intrathecal morphine to be effective."},{"text":"Cramping abdominal pain after bowel surgery is always neuropathic and unresponsive to any regional technique","label":"C","correct":false,"rationale":"Postoperative deep abdominal cramping is predominantly visceral nociceptive pain, not neuropathic, and it can respond to techniques that cover visceral afferents such as a thoracic epidural."},{"text":"Local anesthetic from a TAP block is too rapidly absorbed to provide any meaningful duration of analgesia","label":"D","correct":false,"rationale":"A TAP block provides hours of somatic analgesia, as evidenced by this patient''s well-controlled incisional pain, so inadequate duration does not explain the persistent visceral pain."},{"text":"The TAP block anesthetizes the thoracolumbar somatic nerves of the abdominal wall but does not block visceral afferents","label":"E","correct":true,"rationale":"The TAP block deposits local anesthetic around the T6–L1 somatic nerves supplying the anterior and lateral abdominal wall and parietal peritoneum, so it relieves incisional somatic pain but does not cover visceral afferent pain from the bowel."}]'::jsonb, 'E', 'The TAP block targets the somatic thoracolumbar nerves (approximately T6–L1) coursing in the plane between the internal oblique and transversus abdominis muscles, providing analgesia to the anterior and lateral abdominal wall and parietal peritoneum. A key, frequently tested limitation is that it provides somatic but not visceral analgesia. After bowel surgery, deep cramping mid-abdominal pain arises from visceral afferents and will not be covered by a TAP block; a technique that blocks visceral afferents, such as a thoracic epidural, is needed for that component.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK547730/","source":"Transversus Abdominis Plane Block - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-036', 'Regional & Pain', 'Regional & Pain', 'Subspecialty Care', 'Post-dural puncture headache (neuraxial complication)', 'easy', 'A 24-year-old healthy woman receives a labor epidural. During placement using a loss-of-resistance technique with a 17-gauge Tuohy needle, there is an unintended dural puncture with free flow of cerebrospinal fluid. The epidural is resited at an adjacent interspace and labor proceeds uneventfully. On the second postpartum day she develops a bilateral fronto-occipital headache that is markedly worse when she sits or stands and is relieved within minutes of lying flat; she also reports mild neck stiffness and tinnitus. Her neurologic exam is otherwise normal and she is afebrile. Which feature of this case is most strongly associated with the highest risk of developing this complication?', '[{"text":"Accidental dural puncture with a large-gauge cutting epidural (Tuohy) needle","label":"A","correct":true,"rationale":"Larger-gauge needles and cutting (non-pencil-point) tips cause a bigger dural defect and greater cerebrospinal fluid leak, and an accidental wet tap with a 17-gauge Tuohy needle carries a high incidence of post-dural puncture headache."},{"text":"Her use of a labor epidural rather than a combined spinal-epidural technique","label":"B","correct":false,"rationale":"The analgesic technique label itself does not determine risk; what matters is whether the dura is breached and the size and type of the needle that breaches it."},{"text":"Her supine positioning during epidural placement","label":"C","correct":false,"rationale":"Patient positioning during placement is not an established major determinant of post-dural puncture headache risk."},{"text":"Her relatively low body mass index","label":"D","correct":false,"rationale":"While obesity has a complex relationship with this complication, low BMI is not the dominant risk factor here compared with the large-bore dural breach."},{"text":"The fact that she is afebrile, which favors a low-pressure headache","label":"E","correct":false,"rationale":"Absence of fever helps exclude infectious causes but is not itself a risk factor that increases the likelihood of developing the headache."}]'::jsonb, 'A', 'This is a classic post-dural puncture headache (PDPH): a postural (worse upright, relieved supine) bilateral headache appearing within 5 days of a dural breach, often with neck pain, tinnitus, or other associated symptoms. The single most important risk factor is the dural puncture itself and, in particular, the needle: larger-gauge and cutting (Quincke/Tuohy) needles create a larger dural defect and greater cerebrospinal fluid leak than smaller pencil-point needles, so an accidental wet tap with a 17-gauge Tuohy needle confers a high PDPH incidence. Treatment ranges from conservative measures to a definitive epidural blood patch for severe or persistent cases.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK430925/","source":"Postdural Puncture Headache - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-037', 'Cardiac', 'Cardiac', 'Subspecialty Care', 'Protamine reaction / cardiopulmonary bypass separation', 'hard', 'A 68-year-old man with type 1 diabetes managed on NPH insulin is undergoing on-pump coronary artery bypass grafting. After successful separation from cardiopulmonary bypass, the surgeon requests heparin reversal and the perfusionist begins administering protamine 1 mg per 100 units of total heparin given. Approximately two minutes into the infusion, the systemic arterial pressure falls from 118/64 mmHg to 62/38 mmHg, the pulmonary artery pressure rises from 28/14 mmHg to 52/30 mmHg, central venous pressure climbs to 22 mmHg, and the right ventricle is seen to be acutely distended and hypokinetic on transesophageal echocardiography. Which of the following is the most appropriate immediate intervention?', '[{"text":"Continue the protamine infusion at a faster rate to fully neutralize circulating heparin","label":"A","correct":false,"rationale":"Incorrect: faster protamine delivery worsens the reaction, and protamine itself, not residual heparin, is driving the hemodynamic collapse."},{"text":"Stop the protamine infusion and treat with an inhaled or intravenous pulmonary vasodilator and inotropic/vasopressor support","label":"B","correct":true,"rationale":"Correct: this presentation is a catastrophic (Type III) protamine reaction with pulmonary vasoconstriction and acute right heart failure, so halting protamine and supporting the right ventricle while lowering pulmonary pressures is the immediate priority."},{"text":"Administer additional intravenous heparin and re-establish cardiopulmonary bypass before any other treatment","label":"C","correct":false,"rationale":"Incorrect: although re-heparinization and returning to bypass may become necessary for refractory collapse, the first step is to stop the offending agent and attempt pharmacologic rescue of the right ventricle."},{"text":"Give a rapid 1 L crystalloid bolus to correct presumed hypovolemia","label":"D","correct":false,"rationale":"Incorrect: the right ventricle is already distended with a high central venous pressure, so aggressive volume loading would further overdistend the failing RV and worsen output."},{"text":"Administer intravenous calcium chloride to reverse protamine-induced myocardial depression","label":"E","correct":false,"rationale":"Incorrect: calcium does not address the pulmonary vasoconstriction and complement/thromboxane-mediated mechanism of a severe protamine reaction and will not relieve the RV afterload."}]'::jsonb, 'B', 'Severe (Type III) protamine reactions produce catastrophic pulmonary vasoconstriction with acute right ventricular pressure overload, systemic hypotension, and elevated pulmonary artery pressures, classically within minutes of administration. Patients on NPH insulin (which contains protamine) and those with fish allergy or prior protamine exposure are at higher risk. Immediate management is to stop the protamine, support the right ventricle with inotropes and vasopressors, and reduce RV afterload with a pulmonary vasodilator; re-heparinization and return to bypass are reserved for refractory cases.', '[{"url":"https://www.openanesthesia.org/keywords/protamine-reaction/","source":"Protamine Reactions (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-038', 'Cardiac', 'Cardiac', 'Subspecialty Care', 'Valvular disease: aortic stenosis hemodynamic management', 'medium', 'A 79-year-old woman with severe calcific aortic stenosis (valve area 0.7 cm2, mean gradient 52 mmHg) presents for hip fracture fixation under general anesthesia. Her baseline pressure is 138/82 mmHg and heart rate is 72 bpm in sinus rhythm. Shortly after induction with propofol, her heart rate increases to 124 bpm and is now an irregularly irregular rhythm on the monitor, with the blood pressure falling to 78/50 mmHg. Which of the following best explains why this rhythm is so poorly tolerated in this patient?', '[{"text":"The tachycardia raises myocardial oxygen demand while shortening diastolic coronary perfusion time to the hypertrophied left ventricle","label":"A","correct":false,"rationale":"Incorrect alone: increased demand with reduced diastolic perfusion does contribute to ischemia, but it is not the single best explanation for the abrupt hemodynamic deterioration tied specifically to this rhythm change."},{"text":"Propofol has directly increased systemic vascular resistance, raising afterload across the stenotic valve","label":"B","correct":false,"rationale":"Incorrect: propofol lowers, not raises, systemic vascular resistance, and a fixed valvular obstruction—not changing afterload—is the dominant problem."},{"text":"Loss of the organized atrial contribution to filling of a stiff, hypertrophied left ventricle markedly reduces stroke volume across the fixed obstruction","label":"C","correct":true,"rationale":"Correct: the noncompliant, hypertrophied ventricle in aortic stenosis is heavily dependent on the atrial kick, so the loss of organized atrial contraction in new atrial fibrillation sharply lowers preload, stroke volume, and cardiac output."},{"text":"The increased rate has improved diastolic filling and caused pulmonary edema from volume overload","label":"D","correct":false,"rationale":"Incorrect: tachycardia shortens diastolic filling time rather than improving it, and the acute picture is low output, not volume overload."},{"text":"Aortic stenosis converts the lesion into a volume-overload state in which any tachyarrhythmia causes acute mitral regurgitation","label":"E","correct":false,"rationale":"Incorrect: aortic stenosis is a pressure-overload, not a primary volume-overload lesion, and acute mitral regurgitation is not the mechanism of decompensation here."}]'::jsonb, 'C', 'The hypertrophied, poorly compliant left ventricle of severe aortic stenosis depends heavily on the atrial kick for adequate end-diastolic filling, and on slower heart rates that preserve diastolic filling and coronary perfusion time. New-onset atrial fibrillation removes the organized atrial contribution while the rapid ventricular response shortens diastole, collapsing stroke volume across the fixed obstruction. Management favors maintaining sinus rhythm, avoiding tachycardia and hypotension, and prompt synchronized cardioversion when an acute arrhythmia causes hemodynamic instability.', '[{"url":"https://www.openanesthesia.org/keywords/aortic-stenosis/","source":"Aortic Stenosis: Etiology, Pathophysiology, and Clinical Presentation (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-039', 'Cardiac', 'Cardiac', 'Subspecialty Care', 'Pericardial disease: cardiac tamponade and induction', 'medium', 'A 54-year-old man presents to the operating room for emergency surgical drainage of a large pericardial effusion after a recent type A aortic dissection repair. He is anxious, sitting upright, tachycardic at 128 bpm, with blood pressure 88/70 mmHg, jugular venous distension, and pulsus paradoxus of 18 mmHg; echocardiography shows diastolic right atrial and right ventricular collapse. Which of the following is the most appropriate anesthetic management strategy for induction?', '[{"text":"Perform a standard rapid-sequence induction with propofol and full positive-pressure ventilation immediately after preoxygenation","label":"A","correct":false,"rationale":"Incorrect: propofol-induced vasodilation and myocardial depression plus positive-pressure ventilation can abolish the compensatory tachycardia and preload, precipitating cardiovascular collapse in tamponade."},{"text":"Induce deep general anesthesia and deliberately lower the heart rate with a beta-blocker to improve diastolic filling","label":"B","correct":false,"rationale":"Incorrect: the tachycardia is a compensatory mechanism to maintain cardiac output with a fixed low stroke volume, and slowing the heart rate would reduce output and can be fatal."},{"text":"Give a large dose of an intravenous vasodilator before induction to reduce afterload and augment forward flow","label":"C","correct":false,"rationale":"Incorrect: patients with tamponade are preload-dependent and rely on systemic vascular resistance, so vasodilation can precipitate profound hypotension."},{"text":"Prepare and surgically drain the pericardium under local anesthesia before induction whenever feasible, maintaining spontaneous ventilation and using a hemodynamically stable induction technique","label":"D","correct":true,"rationale":"Correct: relieving the tamponade physiology before or at the moment of induction, while preserving preload, heart rate, contractility, and spontaneous ventilation, is the safest approach to avoid hemodynamic collapse."},{"text":"Aggressively diurese the patient before induction to reduce the pericardial fluid burden","label":"E","correct":false,"rationale":"Incorrect: diuresis reduces the preload that a preload-dependent tamponade patient depends on and does nothing to remove pericardial fluid, risking collapse."}]'::jsonb, 'D', 'Cardiac tamponade impairs diastolic filling, leaving patients dependent on maintained preload, an elevated heart rate, contractility, and systemic vascular resistance, with spontaneous negative-pressure ventilation favoring venous return. The safest strategy is to relieve the effusion before committing to general anesthesia and positive-pressure ventilation—ideally prepping and draining under local anesthesia with the surgeon ready—while using an induction that preserves these compensatory mechanisms. Propofol boluses, deliberate bradycardia, vasodilators, diuresis, and early positive-pressure ventilation can each abolish compensation and cause arrest.', '[{"url":"https://www.openanesthesia.org/keywords/cardiac-tamponade/","source":"Cardiac Tamponade (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-040', 'Monitoring, Equipment & Physiology', 'Monitoring, Equipment & Physiology', 'Subspecialty Care', 'Pulse oximetry physiology and limitations (dyshemoglobins)', 'medium', 'A 58-year-old woman with a 40-pack-year smoking history is in the PACU after an open hemicolectomy. She is somnolent but arousable on a 40% Venturi mask. The pulse oximeter reads SpO2 98% with a strong plethysmographic waveform, yet she appears dusky and her respiratory rate is 8/min. An arterial blood gas drawn simultaneously shows PaO2 95 mmHg, PaCO2 64 mmHg, pH 7.28, and a co-oximetry carboxyhemoglobin (COHb) level of 22%. Which statement best explains the discrepancy between the reassuring pulse oximeter reading and the patient''s clinical appearance?', '[{"text":"The pulse oximeter is reading falsely high because methemoglobin drives the SpO2 toward 85% regardless of true saturation","label":"A","correct":false,"rationale":"Methemoglobin pulls a standard two-wavelength oximeter toward roughly 85%, not 98%, and the elevated species here is carboxyhemoglobin, not methemoglobin."},{"text":"The strong plethysmographic waveform confirms the SpO2 is accurate, so the dusky appearance must be from peripheral vasoconstriction alone","label":"B","correct":false,"rationale":"A good waveform confirms an adequate pulsatile signal but says nothing about whether absorbed light is being misattributed to oxyhemoglobin, so it cannot validate accuracy in the presence of dyshemoglobins."},{"text":"The elevated PaCO2 has shifted the oxyhemoglobin dissociation curve, causing the oximeter to overread saturation","label":"C","correct":false,"rationale":"A rightward Bohr shift changes the PaO2 at which hemoglobin is saturated but does not cause the optical overestimation seen here; the oximeter error is due to the dyshemoglobin, not the curve position."},{"text":"Because PaO2 is normal at 95 mmHg, the SpO2 of 98% is appropriate and no occult abnormality is present","label":"D","correct":false,"rationale":"PaO2 reflects dissolved oxygen tension, not hemoglobin''s oxygen-carrying capacity, so a normal PaO2 cannot reassure when 22% of hemoglobin is bound to carbon monoxide and unavailable for transport."},{"text":"A conventional two-wavelength pulse oximeter cannot distinguish carboxyhemoglobin from oxyhemoglobin, so it overestimates true oxygen saturation when COHb is elevated","label":"E","correct":true,"rationale":"Carboxyhemoglobin absorbs 660-nm light almost identically to oxyhemoglobin, so a two-wavelength device counts COHb as oxyhemoglobin and reports a falsely high SpO2."}]'::jsonb, 'E', 'Standard pulse oximeters use only two wavelengths (660 nm and 940 nm) and assume blood contains only oxyhemoglobin and deoxyhemoglobin. Carboxyhemoglobin absorbs light at 660 nm almost identically to oxyhemoglobin, so the device misclassifies it as saturated hemoglobin and reports a falsely elevated SpO2 that can remain near normal even with dangerous CO poisoning. Co-oximetry, which uses multiple wavelengths, is required to measure dyshemoglobins, and clinical context (smoke or combustion exposure, headache, somnolence) should prompt its use rather than relying on a reassuring SpO2.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK470348/","source":"Pulse Oximetry (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-041', 'Monitoring, Equipment & Physiology', 'Monitoring, Equipment & Physiology', 'Subspecialty Care', 'Anesthesia breathing circuit equipment (CO2 absorbent desiccation)', 'hard', 'An anesthesiologist assistant returns from a weekend to find the first scheduled case is a sevoflurane general anesthetic delivered through a circle system that was left with the fresh gas flow inadvertently running at 10 L/min over the entire 36-hour period with the vaporizer off. During the preoperative machine check, the soda lime canister feels warm and its color indicator has reverted from violet back to white. Which step most directly reduces the risk of patient harm from anesthetic degradation in this circuit?', '[{"text":"Replace the desiccated absorbent with fresh, properly hydrated absorbent before beginning the anesthetic","label":"A","correct":true,"rationale":"Desiccation is the root cause of accelerated anesthetic breakdown to carbon monoxide and Compound A, so installing fresh hydrated absorbent removes the conditions that generate these toxins."},{"text":"Increase the fresh gas flow during the case to dilute any toxic degradation products that form","label":"B","correct":false,"rationale":"High fresh gas flow through desiccated absorbent does not eliminate the chemistry of degradation and can actually accelerate further drying and exothermic reaction, so it does not reliably protect the patient."},{"text":"Switch the planned agent from sevoflurane to desflurane to avoid Compound A formation","label":"C","correct":false,"rationale":"Desflurane and desiccated strong-base absorbent is the combination most prone to generating high carbon monoxide concentrations, so substituting desflurane trades one hazard for a worse one."},{"text":"Proceed with the case because the reverted (white) color indicator confirms the absorbent is fully regenerated and safe","label":"D","correct":false,"rationale":"Color indicators track pH-driven exhaustion and can revert on standing even when granules remain dangerously desiccated, so a white color does not confirm safety."},{"text":"Add a heat-and-moisture exchanger to the breathing circuit to rehydrate the absorbent during use","label":"E","correct":false,"rationale":"An HME humidifies inspired gas at the patient connection but does not restore water content to the absorbent granules upstream, so it does not correct the desiccation driving degradation."}]'::jsonb, 'A', 'Prolonged high fresh gas flow desiccates carbon dioxide absorbent, and dry strong-base absorbents (those containing sodium or potassium hydroxide) degrade volatile anesthetics into toxic products: sevoflurane forms Compound A (a nephrotoxin) and, more importantly, desiccated absorbent with any agent can generate carbon monoxide, with desflurane producing the highest concentrations. A warm canister and a reverted color indicator are classic warning signs of a desiccated, reacting absorbent. The definitive remedy is to replace the absorbent with fresh hydrated material; modern calcium-hydroxide-based absorbents (e.g., Amsorb) lack strong bases and produce negligible CO and Compound A even when dry.', '[{"url":"https://www.openanesthesia.org/keywords/carbon-dioxide-absorbers/","source":"Carbon Dioxide Absorbers (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-042', 'Monitoring, Equipment & Physiology', 'Monitoring, Equipment & Physiology', 'Subspecialty Care', 'Neuromuscular monitoring (quantitative vs qualitative train-of-four)', 'medium', 'A 71-year-old man with chronic kidney disease undergoes a 3-hour laparoscopic nephrectomy under general anesthesia with rocuronium. At the end of the case the surgeon is closing, and you plan to reverse neuromuscular blockade with neostigmine and glycopyrrolate. Using a qualitative (visual/tactile) peripheral nerve stimulator at the ulnar nerve, you observe 4 of 4 twitches on train-of-four with no detectable fade by hand. The patient is normothermic. Which statement most accurately describes the limitation of this assessment for confirming readiness for extubation?', '[{"text":"A qualitative train-of-four count of 4 with no tactile fade reliably confirms a train-of-four ratio of at least 0.9 and full recovery","label":"A","correct":false,"rationale":"Tactile and visual assessment cannot detect fade once the ratio exceeds roughly 0.4, so 4 twitches without perceived fade is fully compatible with a ratio well below the 0.9 threshold."},{"text":"Quantitative (objective) monitoring is required to confirm a train-of-four ratio of 0.9 or greater, because qualitative assessment cannot detect fade in this range","label":"B","correct":true,"rationale":"Only objective monitors measure the actual twitch-amplitude ratio, and a ratio of at least 0.9 is the validated threshold for adequate recovery that qualitative methods cannot verify."},{"text":"Neostigmine should not be given because a count of 4 of 4 means no residual blockade remains to reverse","label":"C","correct":false,"rationale":"A qualitative count of 4 does not exclude clinically significant residual blockade, and withholding reversal in that setting risks postoperative residual weakness rather than confirming safety."},{"text":"Double-burst stimulation is less sensitive than train-of-four for detecting residual blockade by hand and should not be used","label":"D","correct":false,"rationale":"Double-burst stimulation actually improves tactile detection of fade compared with train-of-four, so this reverses the true relationship between the two qualitative methods."},{"text":"Switching the stimulation site to the facial nerve would give a more conservative estimate of peripheral recovery than the adductor pollicis","label":"E","correct":false,"rationale":"Facial (orbicularis oculi) muscles recover earlier than the adductor pollicis and overestimate recovery, so monitoring there is less conservative and can mask residual peripheral weakness."}]'::jsonb, 'B', 'The train-of-four ratio (the amplitude of the fourth twitch divided by the first) must be 0.9 or greater to confirm adequate recovery and minimize the risk of residual neuromuscular blockade. Human observers can detect fade by sight or touch only up to a ratio of about 0.4; beyond that, a qualitative ''no fade, 4 of 4'' is indistinguishable from a ratio of 0.5 to 0.9, all of which represent inadequate recovery. Quantitative monitors (acceleromyography, electromyography) objectively measure the ratio, and current ASA guidance recommends quantitative monitoring to confirm a ratio of at least 0.9 before extubation, which is especially important in this patient given renal impairment that prolongs rocuronium clearance.', '[{"url":"https://www.openanesthesia.org/keywords/monitoring-depth-of-neuromuscular-blockade/","source":"Monitoring Depth of Neuromuscular Blockade (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-043', 'Geriatric', 'Geriatric', 'Subspecialty Care', 'Age-related pharmacology of IV anesthetics (propofol induction dosing)', 'medium', 'An 82-year-old, 60-kg woman with hypertension and mild chronic kidney disease presents for elective open reduction and internal fixation of a hip fracture. She is alert and cooperative. Baseline vitals: blood pressure 138/76 mmHg, heart rate 72/min, SpO2 96% on room air. The anesthesiologist plans a propofol induction. Compared with a healthy 30-year-old, which adjustment to the propofol induction dose and a correct underlying mechanism best applies to this patient?', '[{"text":"Increase the dose by 30%, because reduced lean body mass enlarges the central compartment and lowers peak plasma concentration","label":"A","correct":false,"rationale":"Incorrect; aging reduces central volume of distribution and increases pharmacodynamic sensitivity, so the required dose falls rather than rises."},{"text":"Use the same weight-based dose, because propofol pharmacodynamics are unchanged by age once dosing is corrected for body weight","label":"B","correct":false,"rationale":"Incorrect; elderly patients are roughly 30% more pharmacodynamically sensitive to propofol independent of weight-based correction, so an unchanged dose risks profound hypotension."},{"text":"Reduce the dose by approximately 40-50% and titrate slowly, because elderly patients have increased pharmacodynamic sensitivity and reduced clearance","label":"C","correct":true,"rationale":"Correct; geriatric patients are about 30% more sensitive to propofol and have slower clearance, so a 40-50% induction-dose reduction with slow titration is recommended."},{"text":"Reduce the dose by 10% only, because the sole relevant change is a modest decline in hepatic blood flow that minimally affects induction","label":"D","correct":false,"rationale":"Incorrect; a 10% reduction underestimates the combined pharmacodynamic and pharmacokinetic changes of aging and still predisposes to hemodynamic collapse."},{"text":"Avoid propofol entirely and substitute full-dose etomidate, because the elderly show markedly increased pharmacodynamic sensitivity to etomidate","label":"E","correct":false,"rationale":"Incorrect; the elderly do NOT show increased pharmacodynamic sensitivity to etomidate (its dose reduction is driven by altered clearance), so this rationale is wrong even though etomidate can be a reasonable hemodynamic choice."}]'::jsonb, 'C', 'Aging produces both pharmacokinetic changes (smaller central compartment, reduced clearance, increased body fat) and pharmacodynamic changes (about 30% greater brain sensitivity) for propofol. The net effect is that elderly patients require substantially less propofol for induction, and the dose should be reduced roughly 40-50% and given slowly to avoid exaggerated hypotension. Notably, the increased sensitivity is agent-specific: etomidate dose reductions in the elderly are driven by altered clearance, not heightened pharmacodynamic sensitivity.', '[{"url":"https://www.openanesthesia.org/keywords/pharmacological-changes-with-aging-inhalational-and-intravenous-anesthetics/","source":"Pharmacological Changes With Aging: Inhalational and Intravenous Anesthetics (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-044', 'Geriatric', 'Geriatric', 'Subspecialty Care', 'Postoperative delirium prevention and management', 'easy', 'A 79-year-old man with hypertension and baseline mild cognitive impairment undergoes uncomplicated colonic resection under general anesthesia. On postoperative day 2 he becomes acutely confused and inattentive, with fluctuating consciousness and visual hallucinations that worsen at night. He is afebrile, SpO2 is 95% on 2 L/min nasal cannula, basic metabolic panel and glucose are normal, and his bladder is not distended. He is agitated and pulling at lines. Which intervention is the most appropriate FIRST step in management?', '[{"text":"Administer a scheduled benzodiazepine such as lorazepam to control agitation and promote sleep","label":"A","correct":false,"rationale":"Incorrect; benzodiazepines are a recognized precipitant of delirium in the elderly and typically worsen, not improve, the condition."},{"text":"Start scheduled diphenhydramine at bedtime to treat the nocturnal worsening","label":"B","correct":false,"rationale":"Incorrect; anticholinergic agents like diphenhydramine reduce central cholinergic tone and can precipitate or aggravate delirium in older adults."},{"text":"Apply physical (wrist) restraints to prevent line removal and ensure safety","label":"C","correct":false,"rationale":"Incorrect; restraints are associated with prolonged and more severe delirium and should be avoided except as a brief last resort when safety cannot otherwise be ensured."},{"text":"Implement nonpharmacologic measures: reorientation, restore hearing/visual aids, normalize the sleep-wake cycle, and mobilize early","label":"D","correct":true,"rationale":"Correct; multicomponent nonpharmacologic strategies are first-line for postoperative delirium and address the modifiable precipitating factors before drugs are considered."},{"text":"Order an urgent head CT to evaluate for a structural cause before any other intervention","label":"E","correct":false,"rationale":"Incorrect; with a classic fluctuating presentation and no focal deficits or red flags, imaging is low-yield as the first step, whereas reversible precipitants and nonpharmacologic care take priority."}]'::jsonb, 'D', 'Postoperative delirium is an acute, fluctuating disturbance of attention and awareness common in older surgical patients, and management begins with identifying and correcting precipitants (hypoxia, pain, infection, metabolic derangement, urinary retention) combined with multicomponent nonpharmacologic care. Reorientation, sensory aids, sleep-wake normalization, and early mobilization are first-line. Deliriogenic drugs such as benzodiazepines and anticholinergics should be avoided, and physical restraints can worsen and prolong delirium.', '[{"url":"https://www.openanesthesia.org/keywords/postoperative-delirium/","source":"Postoperative Delirium in the Aging Patient (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-045', 'Geriatric', 'Geriatric', 'Subspecialty Care', 'Perioperative cardiovascular risk management (beta-blocker continuation vs initiation)', 'hard', 'A 75-year-old man with stable coronary artery disease, hypertension, and a remote drug-eluting stent presents for elective open inguinal hernia repair. He has taken metoprolol succinate 100 mg daily for three years; his resting heart rate is 58/min and blood pressure is 132/74 mmHg. The surgical resident asks whether to hold the metoprolol on the morning of surgery and whether a new high-dose beta-blocker should be started preoperatively to further lower cardiac risk. What is the most appropriate perioperative beta-blocker management?', '[{"text":"Hold the metoprolol on the morning of surgery and resume it postoperatively to prevent intraoperative bradycardia","label":"A","correct":false,"rationale":"Incorrect; abruptly stopping chronic beta-blockade risks rebound tachycardia, hypertension, and ischemia, so it should be continued rather than held."},{"text":"Continue the metoprolol and additionally start high-dose extended-release metoprolol the morning of surgery to maximize cardioprotection","label":"B","correct":false,"rationale":"Incorrect; starting high-dose beta-blockade on the day of surgery is exactly the POISE regimen that reduced nonfatal MI but increased total mortality and stroke."},{"text":"Discontinue the metoprolol one week before surgery to allow full recovery of chronotropic reserve","label":"C","correct":false,"rationale":"Incorrect; planned discontinuation of chronic beta-blockade removes its protective effect and risks withdrawal phenomena and perioperative ischemia."},{"text":"Switch him to a single preoperative dose of intravenous esmolol on arrival in place of his oral metoprolol","label":"D","correct":false,"rationale":"Incorrect; there is no indication to replace effective stable oral therapy with a short-acting agent, and this does not address the core question of continuation versus new initiation."},{"text":"Continue his chronic metoprolol through the perioperative period and do NOT initiate a new high-dose beta-blocker","label":"E","correct":true,"rationale":"Correct; chronic beta-blockade should be continued to avoid withdrawal, while fresh high-dose initiation just before surgery increased stroke and mortality in the POISE trial and is not recommended."}]'::jsonb, 'E', 'Patients already on chronic beta-blockers should have them continued throughout the perioperative period, because abrupt withdrawal causes rebound adrenergic activity and ischemia. In contrast, de novo initiation of high-dose beta-blockade shortly before noncardiac surgery is harmful: the POISE trial showed that fixed high-dose metoprolol started just before surgery reduced nonfatal MI but increased overall mortality and stroke, largely from hypotension and bradycardia. This continue-but-do-not-newly-initiate principle is especially relevant in older patients with established coronary disease.', '[{"url":"https://www.openanesthesia.org/keywords/perioperative-myocardial-infarction/","source":"Perioperative Myocardial Infarction (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb);
